    if (query[0] === 1) {
      const x = query[1];
      if (online[x]) {
        result.push(x);
      } else {
        // Find the minimum online node in the same connected component
        const visited = new Set();
        const queue = [x];
        visited.add(x);
        let minNode = -1;
        while (queue.length > 0) {
          const current = queue.pop();
          if (online[current]) {
            minNode = minNode === -1 || current < minNode ? current : minNode;
